      {
            "id": "NRW-LI-010",
            "category": "Building Code",
            "requirement": "Entwässerung und Abwasser: Betriebswässer aus gewerblichen Prozessen (Kühlwasser, Prozessabwasser, ölhaltiges Waschwasser) müssen vor Einleitung in den Kanal vorbehandelt werden.",
            "detail": "WHG § 57; Abwasserverordnung (AbwV) Anhänge; kommunale Einleitungsbedingungen: Leichtstoffabscheider (DIN 1999) für ölhaltige Betriebsabwässer Pflicht. Prozessabwässer mit anderen Schadstoffen (Schwermetalle, Lösemittel): spezifische Vorbehandlung nach AbwV. Grenzwerte im Direkteinleitungsfall: spezifisch nach Branche (AbwV Anhang). Indirekteinleitung in öffentliche Kanalisation: Grenzwerte nach kommunaler Satzung. Regenwasser von kontaminierten Betriebsflächen getrennt sammeln.",
            "source_law": "WHG §§ 57, 58; AbwV; DIN 1999-100; kommunale Entwässerungssatzung",
            "source_url": "https://www.gesetze-im-internet.de/whg_2009/",
            "last_verified": "2026-03-25",
            "applies_to_funding": false
      }
